import{_ as t,a,b as d,c as i}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as r,o,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Add a WebDAV Channel","description":"","frontmatter":{},"headers":[],"relativePath":"en/upload/webdav.md","filePath":"en/upload/webdav.md","lastUpdated":1781962217000}'),l={name:"en/upload/webdav.md"};function h(c,e,p,u,f,b){return o(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="add-a-webdav-channel" tabindex="-1">Add a WebDAV Channel <a class="header-anchor" href="#add-a-webdav-channel" aria-label="Permalink to &quot;Add a WebDAV Channel&quot;">​</a></h1><h2 id="best-fit" tabindex="-1">Best Fit <a class="header-anchor" href="#best-fit" aria-label="Permalink to &quot;Best Fit&quot;">​</a></h2><p>Use the WebDAV channel when:</p><ul><li>You have a NAS, cloud drive, or object storage service that provides a WebDAV endpoint.</li><li>You want uploaded images to be stored in your own WebDAV directory.</li><li>You want credentials to be saved in the D1 <code>upload_channels</code> table instead of being exposed long-term in the frontend.</li></ul><h2 id="what-you-need-before-you-start" tabindex="-1">What You Need Before You Start <a class="header-anchor" href="#what-you-need-before-you-start" aria-label="Permalink to &quot;What You Need Before You Start&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>The server-side WebDAV URL, for example <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Username</td><td>Used to sign in to the WebDAV service.</td></tr><tr><td>Password</td><td>Used to sign in to the WebDAV service.</td></tr><tr><td>Authentication mode</td><td>Default is <code>Basic</code>. Use <code>Digest</code> or auto negotiation only if required by the server.</td></tr><tr><td>Storage directory</td><td>Directory used to store files. Default is <code>imgbed</code>.</td></tr></tbody></table><h2 id="where-to-add-it" tabindex="-1">Where to Add It <a class="header-anchor" href="#where-to-add-it" aria-label="Permalink to &quot;Where to Add It&quot;">​</a></h2><ol><li>Open System Settings.</li><li>Go to Upload Settings.</li><li>Click Add Channel in the upper-right corner.</li><li>Select <code>WebDAV</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>What It Does</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>A friendly name for this WebDAV channel, such as <code>koofr</code> or <code>nas</code>.</td><td>Yes</td></tr><tr><td>Endpoint</td><td>Full WebDAV endpoint, including <code>https://</code>.</td><td>Yes</td></tr><tr><td>Username</td><td>WebDAV login username.</td><td>Yes</td></tr><tr><td>Password</td><td>WebDAV login password.</td><td>Yes</td></tr><tr><td>Authentication mode</td><td>Usually <code>Basic</code>; use <code>Digest</code> if the server requires digest authentication.</td><td>Yes</td></tr><tr><td>Storage directory</td><td>Directory where files are stored. Default is <code>imgbed</code>.</td><td>No</td></tr></tbody></table><h2 id="example-fie-nl-tab-digital" tabindex="-1">Example: fie.nl.tab.digital <a class="header-anchor" href="#example-fie-nl-tab-digital" aria-label="Permalink to &quot;Example: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-create-an-app-password" tabindex="-1">1. Create an App Password <a class="header-anchor" href="#_1-create-an-app-password" aria-label="Permalink to &quot;1. Create an App Password&quot;">​</a></h3><p>Open your account security settings, find application passwords, and create a new app password.</p><p><img src="'+t+'" alt="Create an app password" loading="lazy"></p><p>After it is created, copy and save the new app password. It is usually shown only once.</p><p><img src="'+a+'" alt="Save the new app password" loading="lazy"></p><h3 id="_2-fill-in-the-webdav-configuration-in-imgbed" tabindex="-1">2. Fill in the WebDAV Configuration in ImgBed <a class="header-anchor" href="#_2-fill-in-the-webdav-configuration-in-imgbed" aria-label="Permalink to &quot;2. Fill in the WebDAV Configuration in ImgBed&quot;">​</a></h3><p>Return to ImgBed and add a WebDAV channel:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Endpoint</td><td>The WebDAV URL provided by <code>https://fie.nl.tab.digital/</code>.</td></tr><tr><td>Username</td><td>Your WebDAV username.</td></tr><tr><td>Password</td><td>The app password you just created.</td></tr><tr><td>Authentication mode</td><td>Start with <code>Basic</code> in most cases.</td></tr><tr><td>Storage directory</td><td>Default is <code>imgbed</code>; you can also use a custom directory.</td></tr></tbody></table><p><img src="'+d+'" alt="Fill in the configuration" loading="lazy"></p><h2 id="large-file-upload-behavior" tabindex="-1">Large File Upload Behavior <a class="header-anchor" href="#large-file-upload-behavior" aria-label="Permalink to &quot;Large File Upload Behavior&quot;">​</a></h2><p>The WebDAV channel now uses real session-based chunked upload.</p><p>Small files are uploaded as a single complete file. Files larger than 64 MiB are automatically split into chunks of around 10 MiB and uploaded into a remote chunk directory.</p><p>The WebDAV service does not need to support <code>partial update</code> or offset-based writes. ImgBed does not merge chunks into a single large file on the remote server. Instead, it stores a chunk manifest and reads the chunks in order when the file is requested.</p><p>In practice:</p><table tabindex="0"><thead><tr><th>File Size</th><th>Upload Method</th><th>Remote Storage Layout</th></tr></thead><tbody><tr><td>64 MiB or smaller</td><td>Normal upload</td><td>One complete file</td></tr><tr><td>Larger than 64 MiB</td><td>Real session chunked upload</td><td>A chunk directory containing multiple chunk files</td></tr></tbody></table><p>The chunk directory only affects the remote storage layout. It does not change the file URL in ImgBed. Users still access the file through the original <code>/file/...</code> link.</p><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Open Upload Settings.</li><li>Click Add Channel.</li><li>Select <code>WebDAV</code>.</li><li>Enter a channel name you can recognize, for example <code>koofr</code>.</li><li>Enter the WebDAV endpoint, for example <code>https://app.koofr.net/dav/Koofr</code>.</li><li>Enter the username and password.</li><li>Keep authentication mode as <code>Basic</code> by default.</li><li>Keep the storage directory as <code>imgbed</code>, or change it to your own directory.</li><li>Click Save.</li><li>After saving, check the channel card, query capacity if available, and upload a test file.</li></ol><h2 id="how-to-verify-it" tabindex="-1">How to Verify It <a class="header-anchor" href="#how-to-verify-it" aria-label="Permalink to &quot;How to Verify It&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>How to Verify</th></tr></thead><tbody><tr><td>Channel card appears</td><td>After saving, the Upload Settings page should show a WebDAV channel card.</td></tr><tr><td>Channel is enabled</td><td>The switch in the upper-right corner of the card should stay on.</td></tr><tr><td>Credentials are saved</td><td>The detail view should show Endpoint, username, authentication mode, and storage directory.</td></tr><tr><td>Small file upload works</td><td>Upload a test image and confirm that the file appears in the WebDAV directory.</td></tr><tr><td>Large file rule works</td><td>Files larger than 64 MiB use chunked upload and create a remote chunk directory.</td></tr><tr><td>Capacity query works</td><td>If the server supports capacity information, the query will show used and total capacity.</td></tr></tbody></table><p><img src="'+i+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="why-do-large-webdav-files-create-a-chunk-directory" tabindex="-1">Why do large WebDAV files create a chunk directory? <a class="header-anchor" href="#why-do-large-webdav-files-create-a-chunk-directory" aria-label="Permalink to &quot;Why do large WebDAV files create a chunk directory?&quot;">​</a></h3><p>This is the current storage method for large files.</p><p>Files larger than 64 MiB are not merged into one large remote file. They are stored as a chunk directory. ImgBed records the chunk manifest and returns the complete content by reading the chunks in order.</p><h3 id="what-should-i-check-first-if-large-file-upload-fails" tabindex="-1">What should I check first if large file upload fails? <a class="header-anchor" href="#what-should-i-check-first-if-large-file-upload-fails" aria-label="Permalink to &quot;What should I check first if large file upload fails?&quot;">​</a></h3><p>Check the Endpoint, username, password, and storage directory first. Then confirm that the WebDAV service allows directory creation, file writing, and file reading.</p><p>If capacity query fails but small file upload works, the server may simply not support or may restrict capacity reporting. That does not necessarily mean upload is unavailable.</p><h3 id="which-authentication-mode-should-i-use" tabindex="-1">Which authentication mode should I use? <a class="header-anchor" href="#which-authentication-mode-should-i-use" aria-label="Permalink to &quot;Which authentication mode should I use?&quot;">​</a></h3><p>Start with <code>Basic</code>.</p><p>If the server explicitly requires digest authentication, use <code>Digest</code>.</p><p>If you are not sure, use automatic negotiation.</p><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Prepare WebDAV endpoint, username, and password</span></span>
<span class="line"><span>-&gt; Open Upload Settings</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; Select WebDAV</span></span>
<span class="line"><span>-&gt; Enter Endpoint / username / password</span></span>
<span class="line"><span>-&gt; Keep authentication mode as Basic by default</span></span>
<span class="line"><span>-&gt; Keep storage directory as imgbed by default</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Query capacity</span></span>
<span class="line"><span>-&gt; Upload a test file</span></span></code></pre></div>`,45)])])}const w=r(l,[["render",h]]);export{y as __pageData,w as default};
